   104→static void
   105→free_list( char **list )
   106→{
   107→	int	i;
   108→
   109→	if ( list != NULL ) {
   110→		for ( i = 0; list[ i ] != NULL; ++i ) {
   111→			free( list[ i ] );
   112→		}
   113→		free( (char *)list );
   114→	}
   115→}
