   118→static int
   119→file_read( const char *path, struct berval *bv )
   120→{
   121→	FILE		*fp;
   122→	ber_slen_t	rlen;
   123→	int		eof;
   124→
   125→	if (( fp = fopen( path, "r" )) == NULL ) {
   126→	    	perror( path );
   127→		return( -1 );
   128→	}
   129→
   130→	if ( fseek( fp, 0L, SEEK_END ) != 0 ) {
   131→		perror( path );
   132→		fclose( fp );
   133→		return( -1 );
   134→	}
   135→
   136→	bv->bv_len = ftell( fp );
   137→
   138→	if (( bv->bv_val = (char *)malloc( bv->bv_len )) == NULL ) {
   139→		perror( "malloc" );
   140→		fclose( fp );
   141→		return( -1 );
   142→	}
   143→
   144→	if ( fseek( fp, 0L, SEEK_SET ) != 0 ) {
   145→		perror( path );
   146→		fclose( fp );
   147→		return( -1 );
   148→	}
   149→
   150→	rlen = fread( bv->bv_val, 1, bv->bv_len, fp );
   151→	eof = feof( fp );
   152→	fclose( fp );
   153→
   154→	if ( (ber_len_t) rlen != bv->bv_len ) {
   155→		perror( path );
   156→		free( bv->bv_val );
   157→		return( -1 );
   158→	}
   159→
   160→	return( bv->bv_len );
   161→}
